<?php $id=(int)($model_info->id??0);$e=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,"UTF-8");echo form_open(get_uri("grupo_donato/resources/blocks/save"),["id"=>"gd-block-form","class"=>"general-form"]); ?><div class="modal-body clearfix"><div class="container-fluid"><input type="hidden" name="id" value="<?php echo $id; ?>"><input type="hidden" name="resource_id" value="<?php echo (int)$resource_id; ?>"><input type="hidden" name="overlap_override" value="0"><div class="alert alert-info"><?php echo app_lang("gd_unit_timezone").": ".$e($timezone); ?></div>
