</div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-bs-dismiss="modal"><?php echo app_lang("close"); ?></button><button type="submit" class="btn btn-primary"><?php echo app_lang("save"); ?></button></div><?php echo form_close(); ?>
<script>$(document).ready(function(){var f=$("#gd-block-form");f.appForm({onSuccess:function(){ $("#gd-blocks-table").appTable({reload:true});},onError:function(r){if(r.overlap_confirmation_required&&confirm('<?php echo addslashes(app_lang("gd_confirm_overlap_override")); ?>')){f.find('[name=overlap_override]').val('1');setTimeout(function(){f.trigger('submit');},100);}return true;}});});</script>
